<#
.SYNOPSIS
VCF 9.1 NSX VLAN-backed segment Creation Automation.
.DESCRIPTION
Bulk create/delete NSX VLAN-backed L2 segments from CSV. fixes: direct existing-segment lookup by ID, and tries both NSX teaming policy JSON field variants without silently dropping the selected policy.
#>
[CmdletBinding()] param([switch]$NoRelaunch)
$Global:VCFNsxVlanSegmentVersion='1.0.0'; $ErrorActionPreference='Stop'; $ProgressPreference='SilentlyContinue'
try{$pwsh=(Get-Process -Id $PID -EA SilentlyContinue).Path;if(-not $pwsh){$pwsh='pwsh.exe'}}catch{$pwsh='pwsh.exe'}
try{if(-not $NoRelaunch -and [Threading.Thread]::CurrentThread.ApartmentState -ne 'STA'){& $pwsh -NoProfile -ExecutionPolicy Bypass -STA -File "$PSCommandPath" -NoRelaunch;exit $LASTEXITCODE}}catch{}
$script:ReportsBase=(Get-Location).Path;$script:RunDir=$null;$Global:LogFile=$null;$script:NsxSession=$null;$script:TransportZoneMap=@{};$script:TransportZoneObjects=@{};$script:AllProfilePolicyNames=@();$script:CsvRows=@();$script:ValidatedRows=@()
function New-RunDir{param([string]$Base) if([string]::IsNullOrWhiteSpace($Base)-or -not(Test-Path -LiteralPath $Base)){$Base=(Get-Location).Path};$d=Join-Path $Base ("NSXVlanSegments-Run-"+(Get-Date -Format 'yyyyMMdd-HHmmss'));New-Item -ItemType Directory -Force -Path $d|Out-Null;$Global:LogFile=Join-Path $d ("NSXVlanSegments-"+(Get-Date -Format 'yyyyMMdd-HHmmss')+'.log');''|Set-Content $Global:LogFile -Encoding UTF8;$script:RunDir=$d;$d}
function Write-Log{param([string]$Message,[ValidateSet('INFO','WARN','ERROR')][string]$Level='INFO')$line="[{0}][{1}] {2}"-f(Get-Date).ToString('yyyy-MM-dd HH:mm:ss.fff'),$Level,$Message;try{if($Global:LogFile){Add-Content $Global:LogFile $line -Encoding UTF8}}catch{};try{if($script:txtLog){$script:txtLog.AppendText("$line`r`n");$script:txtLog.ScrollToEnd()}}catch{};Write-Host $line}
function Set-StatusText{param($Label,[string]$Text,[string]$State)if(-not $Label){return};$Label.Text=$Text;$bc=[Windows.Media.BrushConverter]::new();$Label.Foreground=$bc.ConvertFromString($(if($State-eq'OK'){'#7FD37F'}elseif($State-eq'FAIL'){'#D97878'}elseif($State-eq'WARN'){'#D6C15A'}else{'#E6E6E6'}))}
function Set-RunStatus{param([string]$Text='Ready',[string]$State='Ready')if($script:lblRunStatus){$script:lblRunStatus.Text=$Text;$script:lblRunStatus.Foreground=[Windows.Media.BrushConverter]::new().ConvertFromString($(if($State-eq'Running'){'#6FA8DC'}elseif($State-eq'Failed'){'#D97878'}else{'#7FD37F'}))}}
function Show-InfoMessage{param([string]$Message,[string]$Title='NSX VLAN Segment Automation')[System.Windows.MessageBox]::Show($Message,$Title,'OK','Information')|Out-Null}
function Show-ErrorMessage{param([string]$Message,[string]$Title='NSX VLAN Segment Automation')[System.Windows.MessageBox]::Show($Message,$Title,'OK','Error')|Out-Null}
function Set-Busy{param([bool]$Busy)foreach($c in @($script:btnRecheck,$script:btnConnectNsx,$script:btnBrowseCsv,$script:btnLoadCsv,$script:btnValidateCsv,$script:btnExecute,$script:btnBrowseReports,$script:btnOpenOut,$script:btnSampleCsv)){if($c){$c.IsEnabled=-not $Busy}};if($Busy){Set-RunStatus Running Running}else{Set-RunStatus Ready Ready;Refresh-UIState}}
function Prereq-Check{if($PSVersionTable.PSVersion.Major-ge 7){Set-StatusText $script:lblPS "PowerShell $($PSVersionTable.PSVersion)" OK}else{Set-StatusText $script:lblPS "PowerShell $($PSVersionTable.PSVersion)" FAIL};Set-StatusText $script:lblWPF '.NET/WPF: OK' OK;Set-StatusText $script:lblCsv 'CSV Import: Built-in' OK;if(Get-Module -ListAvailable -Name VMware.PowerCLI|Select-Object -First 1){Set-StatusText $script:lblPCLI 'VMware.PowerCLI: Found (not required)' OK}else{Set-StatusText $script:lblPCLI 'VMware.PowerCLI: Not required' WARN}}
function Get-HttpErrorDetail{param([object]$Ex)$code='';$snippet='';try{if($Ex.Response -is [System.Net.Http.HttpResponseMessage]){$code=[int]$Ex.Response.StatusCode;$snippet=$Ex.Response.Content.ReadAsStringAsync().Result}elseif($Ex.Response){$code=$Ex.Response.StatusCode.value__}}catch{};try{if(-not $snippet -and $Ex.ErrorDetails.Message){$snippet=$Ex.ErrorDetails.Message}}catch{};if(-not $snippet){$snippet=$Ex.Message};if($snippet.Length-gt 3000){$snippet=$snippet.Substring(0,3000)};[pscustomobject]@{Code=$code;Snippet=$snippet}}
function Invoke-NsxApi{param([psobject]$Session,[ValidateSet('GET','POST','PATCH','PUT','DELETE')][string]$Method='GET',[string]$Path,[object]$Body=$null)$b64=[Convert]::ToBase64String([Text.Encoding]::ASCII.GetBytes(('{0}:{1}'-f $Session.User,$Session.Password)));$headers=@{Authorization="Basic $b64";Accept='application/json'};$uri="$($Session.Base)$Path";try{if($Method-in@('POST','PATCH','PUT')){$json=if($null-ne$Body){$Body|ConvertTo-Json -Depth 100}else{'{}'};return Invoke-RestMethod -Method $Method -Uri $uri -Headers $headers -ContentType 'application/json' -Body $json -SkipCertificateCheck};return Invoke-RestMethod -Method $Method -Uri $uri -Headers $headers -SkipCertificateCheck}catch{$d=Get-HttpErrorDetail $_.Exception;throw "NSX API call failed: $Method $Path -> HTTP $($d.Code) $($d.Snippet)"}}
function New-NsxSession{param([string]$NsxHost,[string]$Username,[string]$Password)if([string]::IsNullOrWhiteSpace($NsxHost)){throw 'NSX Manager host/FQDN is required.'};$s=[pscustomobject]@{Base="https://$NsxHost";Host=$NsxHost;User=$Username;Password=$Password};$null=Invoke-NsxApi -Session $s -Method GET -Path '/policy/api/v1/infra';$s}
function Get-NsxCollectionItems{param([object]$Response)if($null-eq$Response){return @()};foreach($p in @('results','elements','transport_zones','host_switch_profiles')){if($Response.PSObject.Properties.Name -contains $p -and $Response.$p){return @($Response.$p)}};@($Response)}
function ConvertTo-FlatPairs{param([object]$Obj,[string]$Prefix='')$pairs=[System.Collections.Generic.List[object]]::new();if($null-eq$Obj){return $pairs};if($Obj -is [System.Collections.IDictionary]){foreach($k in $Obj.Keys){$p=if($Prefix){"$Prefix.$k"}else{[string]$k};foreach($c in (ConvertTo-FlatPairs $Obj[$k] $p)){$pairs.Add($c)}};return $pairs};if($Obj -is [pscustomobject]){foreach($pr in $Obj.PSObject.Properties){$p=if($Prefix){"$Prefix.$($pr.Name)"}else{[string]$pr.Name};foreach($c in (ConvertTo-FlatPairs $pr.Value $p)){$pairs.Add($c)}};return $pairs};if($Obj -is [System.Collections.IEnumerable] -and $Obj -isnot [string]){$i=0;foreach($item in $Obj){$p="{0}[{1}]"-f$Prefix,$i;foreach($c in (ConvertTo-FlatPairs $item $p)){$pairs.Add($c)};$i++};return $pairs};$pairs.Add([pscustomobject]@{Path=$Prefix;Value=$Obj})|Out-Null;$pairs}
function Get-NsxTransportZones{param([psobject]$Session)$zones=@();foreach($p in @('/policy/api/v1/infra/sites/default/enforcement-points/default/transport-zones','/api/v1/transport-zones')){try{$resp=Invoke-NsxApi -Session $Session -Method GET -Path $p;foreach($z in (Get-NsxCollectionItems $resp)){$text=($z|ConvertTo-Json -Depth 30 -Compress);$tt=[string](@($z.transport_type,$z.transportType,$z.host_switch_mode)|?{$_}|select -First 1);if($tt-match'VLAN'-or$text-match'VLAN_BACKED|VLAN'){$id=[string](@($z.id,$z.unique_id,$z.display_name,$z.name)|?{$_}|select -First 1);$name=[string](@($z.display_name,$z.name,$z.id)|?{$_}|select -First 1);$path=[string]$z.path;if(-not$path-and$id){$path="/infra/sites/default/enforcement-points/default/transport-zones/$id"};if($id-and$path){$zones+=[pscustomobject]@{Name=$name;Id=$id;Path=$path;Raw=$z}}}};if($zones.Count){break}}catch{Write-Log "Transport zone endpoint unavailable: $p : $($_.Exception.Message)" WARN}};@($zones|sort Name -Unique)}
function Get-NsxProfileNamedTeamings{param([psobject]$Session)$names=@();foreach($path in @('/policy/api/v1/infra/host-switch-profiles','/api/v1/host-switch-profiles')){try{$resp=Invoke-NsxApi -Session $Session -Method GET -Path $path;foreach($profile in (Get-NsxCollectionItems $resp)){foreach($f in @(ConvertTo-FlatPairs $profile)){$fp=[string]$f.Path;$fv=([string]$f.Value).Trim();if($fp-match'(named_teamings|namedTeamings|teaming).*\.name$'-and$fv-and$fv-notmatch'^(FAILOVER|LOADBALANCE|ORDER|SRC|LACP|ENS|DEFAULT)$'){$names+=$fv}}}}catch{Write-Log "Named teaming profile endpoint warning: $path : $($_.Exception.Message)" WARN}};@($names|?{$_}|select -Unique|sort)}
function Get-TeamingPolicyNamesFromTransportZone{param($TransportZoneObject)$names=@();if(-not$TransportZoneObject){return @()};foreach($f in @(ConvertTo-FlatPairs $TransportZoneObject)){$p=[string]$f.Path;$v=([string]$f.Value).Trim();if($v-and$p-match'uplink.*teaming.*policy.*names|uplink_teaming_policy_names|uplinkTeamingPolicyNames|teaming.*names'){if($v-notmatch'System\.Object|@\{|\[\]' -and $v.Length-lt128){$names+=$v}}};@($names|select -Unique|sort)}
function Refresh-TeamingPolicyDropdownForSelectedTz{if(-not$script:cmbTeamingPolicy -or -not$script:cmbTransportZone.SelectedItem){return};$label=[string]$script:cmbTransportZone.SelectedItem;$tzObj=$script:TransportZoneObjects[$label];$tzPolicyNames=@(Get-TeamingPolicyNamesFromTransportZone $tzObj);$script:cmbTeamingPolicy.Items.Clear();[void]$script:cmbTeamingPolicy.Items.Add('DEFAULT - no uplink teaming override');foreach($n in $tzPolicyNames){[void]$script:cmbTeamingPolicy.Items.Add($n)};if($tzPolicyNames.Count-eq0 -and $script:AllProfilePolicyNames.Count){foreach($n in $script:AllProfilePolicyNames){[void]$script:cmbTeamingPolicy.Items.Add("UNVERIFIED: $n")};Write-Log 'Selected transport zone did not expose Uplink Teaming Policy Names. Showing profile-derived policies as UNVERIFIED; NSX may reject them unless they are configured on the transport zone.' WARN};if($script:cmbTeamingPolicy.Items.Count-gt1){$script:cmbTeamingPolicy.SelectedIndex=1}else{$script:cmbTeamingPolicy.SelectedIndex=0};Write-Log "Teaming policy dropdown refreshed for transport zone '$label'. TZ policy count=$($tzPolicyNames.Count)."}
function Get-SelectedTeamingPolicyName{if(-not$script:cmbTeamingPolicy.SelectedItem){return ''};$v=[string]$script:cmbTeamingPolicy.SelectedItem;if($v-like'DEFAULT*'){return ''};if($v-like'UNVERIFIED:*'){return $v.Substring('UNVERIFIED:'.Length).Trim()};$v.Trim()}
function ConvertTo-SegmentId{param([string]$Name)$id=$Name.Trim().ToLowerInvariant()-replace'[^a-z0-9_.-]+','-';$id=$id.Trim('-');if([string]::IsNullOrWhiteSpace($id)){throw "Segment name '$Name' cannot be converted to a valid NSX ID."};$id}
function Get-NsxSegmentExisting{param([psobject]$Session,[string]$SegmentId,[string]$DisplayName)try{return Invoke-NsxApi -Session $Session -Method GET -Path "/policy/api/v1/infra/segments/$SegmentId"}catch{if($_.Exception.Message -notmatch '404|NOT_FOUND|not found'){Write-Log "Direct segment lookup warning for '$SegmentId': $($_.Exception.Message)" WARN}};try{$resp=Invoke-NsxApi -Session $Session -Method GET -Path '/policy/api/v1/infra/segments';return (@(Get-NsxCollectionItems $resp)|?{([string]$_.display_name).Trim() -ieq $DisplayName.Trim()}|select -First 1)}catch{Write-Log "Segment display_name lookup failed for '$DisplayName': $($_.Exception.Message)" WARN;$null}}
function New-VlanSegmentSpec{param([string]$SegmentName,[int]$Vlan,[string]$Description,[ValidateSet(0,1)][int]$AdminState,[string]$TransportZonePath,[string]$UplinkTeamingPolicyName,[string]$TeamingField='uplink_teaming_policy_name')$adv=[ordered]@{connectivity='ON'};if($UplinkTeamingPolicyName){$adv[$TeamingField]=$UplinkTeamingPolicyName};[pscustomobject][ordered]@{display_name=$SegmentName;description=$Description;transport_zone_path=$TransportZonePath;vlan_ids=@([string]$Vlan);admin_state=$(if($AdminState-eq1){'UP'}else{'DOWN'});advanced_config=$adv}}
function Get-PropertyValueInsensitive{param([object]$Row,[string[]]$Names)foreach($n in $Names){$p=$Row.PSObject.Properties|?{$_.Name -ieq $n}|select -First 1;if($p){return $p.Value}};$null}
function Test-Flag01{param([object]$Value,[string]$Field)$s=([string]$Value).Trim();if($s-notin@('0','1')){throw "$Field must be 0 or 1. Found '$s'."};[int]$s}
function Import-SegmentCsv{param([string]$Path)if([string]::IsNullOrWhiteSpace($Path)-or -not(Test-Path -LiteralPath $Path)){throw 'Select a valid CSV file.'};$rows=@(Import-Csv -LiteralPath $Path);if(-not$rows.Count){throw 'CSV contains no rows.'};$script:CsvRows=$rows;Write-Log "Loaded CSV: $Path ($($rows.Count) row(s))";$rows}
function Test-SegmentCsvRows{param([object[]]$Rows)if(-not$script:NsxSession){throw 'Connect to NSX Manager first.'};if(-not$script:cmbTransportZone.SelectedItem){throw 'Select a VLAN transport zone.'};$validated=@();$rowNum=1;foreach($r in @($Rows)){$rowNum++;try{$name=([string](Get-PropertyValueInsensitive $r @('SegmentName','Segment Name','Name','segment_name'))).Trim();$vlanText=([string](Get-PropertyValueInsensitive $r @('VLAN','Vlan','VLANNumber','VLAN Number','vlan_id'))).Trim();$desc=([string](Get-PropertyValueInsensitive $r @('Description','Desc'))).Trim();$admin=Test-Flag01 (Get-PropertyValueInsensitive $r @('AdminState','Admin State','admin_state')) 'AdminState';$state=Test-Flag01 (Get-PropertyValueInsensitive $r @('State','DesiredState','desired_state')) 'State';if([string]::IsNullOrWhiteSpace($name)){throw 'SegmentName is required.'};if($vlanText-notmatch'^\d+$'){throw "VLAN must be an integer from 0-4094. Found '$vlanText'."};$vlan=[int]$vlanText;if($vlan-lt0-or$vlan-gt4094){throw "VLAN must be an integer from 0-4094. Found '$vlanText'."};$validated+=[pscustomobject]@{Row=$rowNum;SegmentName=$name;SegmentId=(ConvertTo-SegmentId $name);VLAN=$vlan;Description=$desc;AdminState=$admin;State=$state;Action=$(if($state-eq1){'CreateOrUpdate'}else{'Delete'});Valid=$true;Message='OK'}}catch{$validated+=[pscustomobject]@{Row=$rowNum;SegmentName='';SegmentId='';VLAN='';Description='';AdminState='';State='';Action='';Valid=$false;Message=$_.Exception.Message};Write-Log "CSV row $rowNum validation failed: $($_.Exception.Message)" ERROR}};$script:ValidatedRows=@($validated);$bad=@($script:ValidatedRows|?{-not$_.Valid});Write-Log "CSV validation complete: $($script:ValidatedRows.Count-$bad.Count) valid, $($bad.Count) invalid.";@($script:ValidatedRows)}
function Invoke-SegmentPlan{param([object[]]$Rows)$tzLabel=[string]$script:cmbTransportZone.SelectedItem;$tzPath=$script:TransportZoneMap[$tzLabel];if(-not$tzPath){throw 'Selected transport zone path was not found.'};$teamPolicy=Get-SelectedTeamingPolicyName;$results=New-Object System.Collections.Generic.List[object];foreach($row in @($Rows|?{$_.Valid})){$status='Skipped';$message='';try{$segPath="/policy/api/v1/infra/segments/$($row.SegmentId)";if($row.State-eq0){Write-Log "Deleting segment '$($row.SegmentName)' id '$($row.SegmentId)'...";try{$null=Invoke-NsxApi -Session $script:NsxSession -Method DELETE -Path $segPath;$status='Deleted';$message='Deleted'}catch{if($_.Exception.Message-match'HTTP\s+404|NOT_FOUND|not found'){$status='NotFound';$message='Segment did not exist; no action taken.';Write-Log "Segment '$($row.SegmentName)' did not exist; delete treated as success." WARN}else{throw}}}else{$existing=Get-NsxSegmentExisting -Session $script:NsxSession -SegmentId $row.SegmentId -DisplayName $row.SegmentName;if($existing){$eid=[string](@($existing.id,$existing.unique_id)|?{$_}|select -First 1);$ep=[string]$existing.path;Write-Log "Segment '$($row.SegmentName)' already exists in NSX. Skipping create/update. Existing id/path: $eid $ep" WARN;$status='SkippedExists';$message="Segment already exists. Existing id/path: $eid $ep"}else{$fields=if($teamPolicy){@('uplink_teaming_policy_name','uplink_teaming_policy')}else{@('')};$lastErr=$null;foreach($field in $fields){$spec=New-VlanSegmentSpec -SegmentName $row.SegmentName -Vlan ([int]$row.VLAN) -Description $row.Description -AdminState ([int]$row.AdminState) -TransportZonePath $tzPath -UplinkTeamingPolicyName $teamPolicy -TeamingField $(if($field){$field}else{'uplink_teaming_policy_name'});$suffix=if($field){$field}else{'no_teaming'};$payloadFile=Join-Path $script:RunDir ("payload_{0}_{1}.json"-f$row.SegmentId,$suffix);$spec|ConvertTo-Json -Depth 50|Set-Content $payloadFile -Encoding UTF8;try{if($teamPolicy){Write-Log "Creating/updating '$($row.SegmentName)' VLAN $($row.VLAN) with teaming policy '$teamPolicy' using field '$field'..."}else{Write-Log "Creating/updating '$($row.SegmentName)' VLAN $($row.VLAN) without teaming override..."};$null=Invoke-NsxApi -Session $script:NsxSession -Method PATCH -Path $segPath -Body $spec;$status='CreatedOrUpdated';$message="Created/updated. Payload: $payloadFile";break}catch{$lastErr=$_.Exception.Message;Write-Log "Attempt failed for '$($row.SegmentName)' with field '$field': $lastErr" WARN}};if($status-ne'CreatedOrUpdated'){throw $lastErr}}}}catch{$status='Failed';$message=$_.Exception.Message;Write-Log "Segment '$($row.SegmentName)' failed: $message" ERROR};$results.Add([pscustomobject]@{Row=$row.Row;SegmentName=$row.SegmentName;SegmentId=$row.SegmentId;VLAN=$row.VLAN;Action=$row.Action;Result=$status;Message=$message})|Out-Null};$out=Join-Path $script:RunDir ("SegmentResults_{0}.csv"-f(Get-Date -Format 'yyyyMMdd-HHmmss'));$results|Export-Csv $out -NoTypeInformation -Encoding UTF8;Write-Log "Segment results saved: $out";[pscustomobject]@{Results=$results.ToArray();Path=[string]$out}}
function New-SampleCsv{param([string]$Path)@([pscustomobject]@{SegmentName='VLAN1005';VLAN=1005;Description='VLAN 1005';AdminState=1;State=1},[pscustomobject]@{SegmentName='Old-VLAN1006';VLAN=1006;Description='Remove old segment';AdminState=0;State=0})|Export-Csv $Path -NoTypeInformation -Encoding UTF8;Write-Log "Sample CSV written: $Path"}
Add-Type -AssemblyName PresentationCore,PresentationFramework,WindowsBase -ErrorAction Stop|Out-Null;Add-Type -AssemblyName System.Windows.Forms -EA SilentlyContinue|Out-Null
$xaml=@"
<Window xmlns="http://schemas.microsoft.com/winfx/2006/xaml/presentation" xmlns:x="http://schemas.microsoft.com/winfx/2006/xaml" Title="VCF 9.1 NSX VLAN-backed segment Creation Automation" Height="820" Width="1240" WindowStartupLocation="CenterScreen" Background="#050A0D" FontFamily="Segoe UI" Foreground="#E6E6E6"><Window.Resources><SolidColorBrush x:Key="Panel2" Color="#0A1418"/><SolidColorBrush x:Key="Accent" Color="#29B6F6"/><SolidColorBrush x:Key="Text" Color="#E6E6E6"/><SolidColorBrush x:Key="Muted" Color="#9CB5C0"/><Style TargetType="TextBlock"><Setter Property="Foreground" Value="{StaticResource Text}"/><Setter Property="Margin" Value="0,4,8,4"/></Style><Style TargetType="TextBox"><Setter Property="Background" Value="#050A0D"/><Setter Property="Foreground" Value="{StaticResource Text}"/><Setter Property="BorderBrush" Value="#607D8B"/><Setter Property="Margin" Value="0,2,8,8"/><Setter Property="Padding" Value="6"/></Style><Style TargetType="PasswordBox"><Setter Property="Background" Value="#050A0D"/><Setter Property="Foreground" Value="{StaticResource Text}"/><Setter Property="BorderBrush" Value="#607D8B"/><Setter Property="Margin" Value="0,2,8,8"/><Setter Property="Padding" Value="6"/></Style><Style TargetType="ComboBox"><Setter Property="Background" Value="#050A0D"/><Setter Property="Foreground" Value="#111111"/><Setter Property="BorderBrush" Value="#607D8B"/><Setter Property="Margin" Value="0,2,8,8"/><Setter Property="Padding" Value="5"/></Style><Style TargetType="Button"><Setter Property="Background" Value="{StaticResource Accent}"/><Setter Property="Foreground" Value="#071218"/><Setter Property="FontWeight" Value="SemiBold"/><Setter Property="BorderThickness" Value="0"/><Setter Property="Padding" Value="12,6"/><Setter Property="Margin" Value="0,4,8,4"/><Setter Property="MinWidth" Value="110"/></Style><Style TargetType="GroupBox"><Setter Property="Foreground" Value="{StaticResource Text}"/><Setter Property="Background" Value="{StaticResource Panel2}"/><Setter Property="BorderBrush" Value="#2B4D59"/><Setter Property="Margin" Value="10"/><Setter Property="Padding" Value="10"/></Style><Style TargetType="DataGrid"><Setter Property="Background" Value="#050A0D"/><Setter Property="Foreground" Value="#E6E6E6"/><Setter Property="RowBackground" Value="#071116"/><Setter Property="AlternatingRowBackground" Value="#0B1A20"/><Setter Property="HeadersVisibility" Value="Column"/></Style><Style TargetType="DataGridColumnHeader"><Setter Property="Background" Value="#0A1418"/><Setter Property="Foreground" Value="#E6E6E6"/><Setter Property="FontWeight" Value="SemiBold"/></Style></Window.Resources><Grid Margin="14"><Grid.RowDefinitions><RowDefinition Height="Auto"/><RowDefinition Height="Auto"/><RowDefinition Height="*"/></Grid.RowDefinitions><Grid Grid.Row="0"><Grid.ColumnDefinitions><ColumnDefinition Width="*"/><ColumnDefinition Width="*"/></Grid.ColumnDefinitions><GroupBox Header="Prerequisites / Output" Grid.Column="0"><Grid><Grid.ColumnDefinitions><ColumnDefinition Width="1*"/><ColumnDefinition Width="1.35*"/></Grid.ColumnDefinitions><GroupBox Header="Prerequisites" Grid.Column="0" Margin="0,0,8,0"><StackPanel><WrapPanel><TextBlock Name="lblPS" Text="PowerShell"/><TextBlock Name="lblWPF" Text="WPF"/><TextBlock Name="lblCsv" Text="CSV"/><TextBlock Name="lblPCLI" Text="PowerCLI"/></WrapPanel><StackPanel Orientation="Horizontal"><Button Name="btnRecheck" Content="Recheck"/><TextBlock Name="lblRunStatus" Text="Ready" FontWeight="SemiBold" Margin="20,8,0,0"/></StackPanel></StackPanel></GroupBox><GroupBox Header="Output" Grid.Column="1" Margin="8,0,0,0"><Grid><Grid.RowDefinitions><RowDefinition Height="Auto"/><RowDefinition Height="Auto"/></Grid.RowDefinitions><StackPanel Grid.Row="0" Orientation="Horizontal"><Button Name="btnBrowseReports" Content="Output Folder"/><Button Name="btnOpenOut" Content="Open Output"/></StackPanel><TextBox Grid.Row="1" Name="txtReportsPath" IsReadOnly="True"/></Grid></GroupBox></Grid></GroupBox><GroupBox Header="NSX Manager Connection" Grid.Column="1"><Grid><Grid.ColumnDefinitions><ColumnDefinition Width="*"/><ColumnDefinition Width="*"/><ColumnDefinition Width="*"/><ColumnDefinition Width="Auto"/></Grid.ColumnDefinitions><Grid.RowDefinitions><RowDefinition Height="Auto"/><RowDefinition Height="Auto"/><RowDefinition Height="Auto"/></Grid.RowDefinitions><TextBlock Grid.Row="0" Grid.Column="0" Text="NSX Manager FQDN/IP"/><TextBlock Grid.Row="0" Grid.Column="1" Text="Username"/><TextBlock Grid.Row="0" Grid.Column="2" Text="Password"/><TextBox Grid.Row="1" Grid.Column="0" Name="txtNsxHost"/><TextBox Grid.Row="1" Grid.Column="1" Name="txtNsxUser" Text="admin"/><PasswordBox Grid.Row="1" Grid.Column="2" Name="pbNsxPass"/><Button Grid.Row="1" Grid.Column="3" Name="btnConnectNsx" Content="Connect"/><TextBlock Grid.Row="2" Grid.ColumnSpan="4" Name="lblNsxStatus" Text="Not connected" Foreground="{StaticResource Muted}"/></Grid></GroupBox></Grid><GroupBox Grid.Row="1" Header="Inventory Selection"><Grid><Grid.ColumnDefinitions><ColumnDefinition Width="2*"/><ColumnDefinition Width="2*"/><ColumnDefinition Width="Auto"/></Grid.ColumnDefinitions><Grid.RowDefinitions><RowDefinition Height="Auto"/><RowDefinition Height="Auto"/></Grid.RowDefinitions><TextBlock Grid.Row="0" Grid.Column="0" Text="VLAN Traffic Type Transport Zone"/><TextBlock Grid.Row="0" Grid.Column="1" Text="Uplink Teaming Policy (from selected TZ)"/><ComboBox Grid.Row="1" Grid.Column="0" Name="cmbTransportZone"/><ComboBox Grid.Row="1" Grid.Column="1" Name="cmbTeamingPolicy"/><TextBlock Grid.Row="1" Grid.Column="2" Name="lblInventorySummary" Text="Connect to NSX to populate inventory" VerticalAlignment="Center" Foreground="{StaticResource Muted}"/></Grid></GroupBox><Grid Grid.Row="2"><Grid.RowDefinitions><RowDefinition Height="Auto"/><RowDefinition Height="*"/></Grid.RowDefinitions><GroupBox Grid.Row="0" Header="CSV Input and Actions"><Grid><Grid.ColumnDefinitions><ColumnDefinition Width="*"/><ColumnDefinition Width="Auto"/><ColumnDefinition Width="Auto"/><ColumnDefinition Width="Auto"/><ColumnDefinition Width="Auto"/><ColumnDefinition Width="Auto"/></Grid.ColumnDefinitions><TextBox Grid.Column="0" Name="txtCsvPath" IsReadOnly="True"/><Button Grid.Column="1" Name="btnBrowseCsv" Content="Browse CSV"/><Button Grid.Column="2" Name="btnLoadCsv" Content="Load CSV"/><Button Grid.Column="3" Name="btnSampleCsv" Content="Sample CSV"/><Button Grid.Column="4" Name="btnValidateCsv" Content="Validate"/><Button Grid.Column="5" Name="btnExecute" Content="Execute"/></Grid></GroupBox><Grid Grid.Row="1"><Grid.ColumnDefinitions><ColumnDefinition Width="1.04*"/><ColumnDefinition Width="0.96*"/></Grid.ColumnDefinitions><GroupBox Grid.Column="0" Header="CSV Preview / Validation"><DataGrid Name="dgPreview" AutoGenerateColumns="True" IsReadOnly="True"/></GroupBox><GroupBox Grid.Column="1" Header="Log"><TextBox Name="txtLog" AcceptsReturn="True" VerticalScrollBarVisibility="Auto" HorizontalScrollBarVisibility="Auto" IsReadOnly="True" FontFamily="Consolas" FontSize="12" TextWrapping="NoWrap"/></GroupBox></Grid></Grid></Grid></Window>
"@
$script:window=[Windows.Markup.XamlReader]::Parse($xaml);foreach($name in @('lblPS','lblWPF','lblCsv','lblPCLI','btnRecheck','btnBrowseReports','btnOpenOut','txtReportsPath','lblRunStatus','txtNsxHost','txtNsxUser','pbNsxPass','btnConnectNsx','lblNsxStatus','cmbTransportZone','cmbTeamingPolicy','lblInventorySummary','txtCsvPath','btnBrowseCsv','btnLoadCsv','btnSampleCsv','btnValidateCsv','btnExecute','dgPreview','txtLog')){Set-Variable -Name $name -Scope Script -Value $script:window.FindName($name)}
function Refresh-UIState{$connected=$null-ne$script:NsxSession;$hasCsv=$script:CsvRows.Count-gt0;$hasTz=[bool]($script:cmbTransportZone-and$script:cmbTransportZone.SelectedItem);$can=[bool]($connected-and$hasCsv-and$hasTz);if($script:btnValidateCsv){$script:btnValidateCsv.IsEnabled=$can};if($script:btnExecute){$script:btnExecute.IsEnabled=$can}}
function Populate-InventoryUi{param([object[]]$TransportZones,[object[]]$ProfilePolicies)$script:cmbTransportZone.Items.Clear();$script:TransportZoneMap=@{};$script:TransportZoneObjects=@{};$script:AllProfilePolicyNames=@($ProfilePolicies);foreach($tz in $TransportZones){$label="$($tz.Name) [$($tz.Id)]";[void]$script:cmbTransportZone.Items.Add($label);$script:TransportZoneMap[$label]=$tz.Path;$script:TransportZoneObjects[$label]=$tz.Raw};if($script:cmbTransportZone.Items.Count-gt0){$script:cmbTransportZone.SelectedIndex=0};Refresh-TeamingPolicyDropdownForSelectedTz;$script:lblInventorySummary.Text="Transport zones: $($TransportZones.Count), profile policies: $($ProfilePolicies.Count)"}
$script:window.Add_ContentRendered({if(-not$script:RunDir){New-RunDir -Base $script:ReportsBase|Out-Null};if($script:txtReportsPath){$script:txtReportsPath.Text=$script:ReportsBase};Prereq-Check;Write-Log "==== NSX VLAN Segment UI started v$Global:VCFNsxVlanSegmentVersion ====";Write-Log "Run folder: $script:RunDir";Set-RunStatus Ready Ready;Refresh-UIState})
$script:btnRecheck.Add_Click({Prereq-Check})
$script:btnBrowseReports.Add_Click({$dlg=New-Object System.Windows.Forms.FolderBrowserDialog;if($dlg.ShowDialog()-eq[System.Windows.Forms.DialogResult]::OK){$script:ReportsBase=$dlg.SelectedPath;$script:txtReportsPath.Text=$script:ReportsBase;New-RunDir -Base $script:ReportsBase|Out-Null;Write-Log "Output folder changed: $script:RunDir"}})
$script:btnOpenOut.Add_Click({try{if(-not$script:RunDir-or-not(Test-Path -LiteralPath $script:RunDir)){throw 'No valid run folder exists yet.'};Start-Process explorer.exe -ArgumentList "`"$script:RunDir`"";Write-Log "Opened output folder: $script:RunDir"}catch{Write-Log "Open Output failed: $($_.Exception.Message)" ERROR;Show-ErrorMessage 'Open Output failed. Check log.'}})
$script:btnConnectNsx.Add_Click({try{Set-Busy $true;$script:NsxSession=New-NsxSession -NsxHost(([string]$script:txtNsxHost.Text).Trim()) -Username(([string]$script:txtNsxUser.Text).Trim()) -Password([string]$script:pbNsxPass.Password);$script:lblNsxStatus.Text="Connected to $($script:txtNsxHost.Text)";$script:lblNsxStatus.Foreground=[Windows.Media.BrushConverter]::new().ConvertFromString('#7FD37F');Write-Log "Connected to NSX Manager: $($script:txtNsxHost.Text)";$tz=@(Get-NsxTransportZones -Session $script:NsxSession);if($tz.Count-eq0){throw 'No VLAN-backed transport zones were found.'};$pol=@(Get-NsxProfileNamedTeamings -Session $script:NsxSession);Populate-InventoryUi -TransportZones $tz -ProfilePolicies $pol;Write-Log "Inventory loaded. VLAN transport zones=$($tz.Count), profile named policies=$($pol.Count).";Set-Busy $false}catch{Set-RunStatus Failed Failed;Write-Log "NSX connect/inventory failed: $($_.Exception.Message)" ERROR;Show-ErrorMessage $_.Exception.Message 'NSX connect failed';Set-Busy $false}})
$script:cmbTransportZone.Add_SelectionChanged({Refresh-TeamingPolicyDropdownForSelectedTz;Refresh-UIState})
$script:cmbTeamingPolicy.Add_SelectionChanged({if($script:cmbTeamingPolicy.SelectedItem){Write-Log "Selected uplink teaming policy: $($script:cmbTeamingPolicy.SelectedItem)" INFO}})
$script:btnBrowseCsv.Add_Click({$dlg=New-Object System.Windows.Forms.OpenFileDialog;$dlg.Filter='CSV files (*.csv)|*.csv|All files (*.*)|*.*';if($dlg.ShowDialog()-eq[System.Windows.Forms.DialogResult]::OK){$script:txtCsvPath.Text=$dlg.FileName}})
$script:btnLoadCsv.Add_Click({try{$rows=Import-SegmentCsv -Path([string]$script:txtCsvPath.Text);$script:dgPreview.ItemsSource=$rows;$script:ValidatedRows=@();Write-Log 'CSV loaded. Click Validate, or click Execute to validate and run.';Refresh-UIState}catch{Write-Log "Load CSV failed: $($_.Exception.Message)" ERROR;Show-ErrorMessage $_.Exception.Message 'Load CSV failed'}})
$script:btnSampleCsv.Add_Click({try{$dlg=New-Object System.Windows.Forms.SaveFileDialog;$dlg.Filter='CSV files (*.csv)|*.csv';$dlg.FileName='nsx-vlan-segments-sample.csv';if($dlg.ShowDialog()-eq[System.Windows.Forms.DialogResult]::OK){New-SampleCsv -Path $dlg.FileName;$script:txtCsvPath.Text=$dlg.FileName;Show-InfoMessage "Sample CSV created:`n$($dlg.FileName)" 'Sample CSV'}}catch{Write-Log "Sample CSV failed: $($_.Exception.Message)" ERROR;Show-ErrorMessage $_.Exception.Message 'Sample CSV failed'}})
$script:btnValidateCsv.Add_Click({try{Set-Busy $true;$v=Test-SegmentCsvRows -Rows $script:CsvRows;$script:dgPreview.ItemsSource=$v;$bad=@($v|?{-not$_.Valid});if($bad.Count){Show-ErrorMessage "Validation completed with $($bad.Count) invalid row(s)." Validation}else{Show-InfoMessage "CSV validation passed for $($v.Count) row(s)." Validation};Set-Busy $false}catch{Write-Log "Validate CSV failed: $($_.Exception.Message)" ERROR;Show-ErrorMessage $_.Exception.Message 'Validate CSV failed';Set-Busy $false}})
$script:btnExecute.Add_Click({try{if(-not$script:ValidatedRows-or$script:ValidatedRows.Count-eq0){$v=Test-SegmentCsvRows -Rows $script:CsvRows;$script:dgPreview.ItemsSource=$v};$invalid=@($script:ValidatedRows|?{-not$_.Valid});if($invalid.Count){throw "CSV validation has $($invalid.Count) invalid row(s)."};$valid=@($script:ValidatedRows|?{$_.Valid});$creates=@($valid|?{$_.State-eq1}).Count;$deletes=@($valid|?{$_.State-eq0}).Count;$policy=Get-SelectedTeamingPolicyName;$policyText=if($policy){"Selected teaming policy '$policy' will be tried using both supported API field names."}else{'No uplink teaming override selected.'};$ans=[System.Windows.MessageBox]::Show("This will create/update $creates and delete $deletes segment(s). Existing names/IDs will be skipped.`n`n$policyText`n`nContinue?",'Execute','YesNo','Warning');if($ans-ne'Yes'){return};Set-Busy $true;$run=Invoke-SegmentPlan -Rows $valid;$failed=@($run.Results|?{$_.Result-eq'Failed'});if($failed.Count){Show-ErrorMessage "Execution completed with $($failed.Count) failure(s). Results:`n$($run.Path)" 'Execute completed with errors'}else{Show-InfoMessage "Execution completed successfully. Results:`n$($run.Path)" 'Execute complete'};Set-Busy $false}catch{Write-Log "Execute failed: $($_.Exception.Message)" ERROR;Show-ErrorMessage $_.Exception.Message 'Execute failed';Set-Busy $false}})
$null=$script:window.ShowDialog()
